#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long ev = N/2;               // floor(N/2)
        long long od = N - ev;            // ceil(N/2)
        unsigned long long ans = 2ULL * od * ev;
        printf("%llu\n", ans);
    }
    return 0;
}

